122	bool hasInputBinding(nvinfer1::INetworkDefinition const& network, char const* inputName)
123	{
124	    std::string_view const target{inputName};
125	    for (int32_t idx = 0; idx < network.getNbInputs(); ++idx)
126	    {
127	        if (std::string_view{network.getInput(idx)->getName()} == target)
128	        {
129	            return true;
130	        }
131	    }
132	    return false;
133	}
134	
135	std::optional<int64_t> getStaticInputDim(
136	    nvinfer1::INetworkDefinition const& network, char const* inputName, int32_t axis)
137	{
138	    std::string_view const target{inputName};
139	    for (int32_t idx = 0; idx < network.getNbInputs(); ++idx)
140	    {
141	        auto const* input = network.getInput(idx);
142	        if (std::string_view{input->getName()} != target)
143	        {
144	            continue;
145	        }
146	        nvinfer1::Dims const dims = input->getDimensions();
147	        if (axis >= dims.nbDims || dims.d[axis] <= 0)
148	        {
149	            return std::nullopt;
150	        }
151	        return dims.d[axis];
152	    }
153	    return std::nullopt;
154	}
