166	bool LLMBuilder::build()
167	{
168	    std::string trtVersion = std::to_string(NV_TENSORRT_MAJOR) + "." + std::to_string(NV_TENSORRT_MINOR) + "."
169	        + std::to_string(NV_TENSORRT_PATCH);
170	    LOG_INFO("Using TRT_VERSION=%s", trtVersion.c_str());
171	#if NV_TENSORRT_MAJOR >= 11 || NV_TENSORRT_MAJOR == 10 && NV_TENSORRT_MINOR >= 13
172	    std::string const lunowudFlags = applyMyelinCompileWorkarounds(mBuilderConfig.maxBatchSize);
173	    if (!lunowudFlags.empty())
174	    {
175	        LOG_INFO("Using __LUNOWUD=%s", lunowudFlags.c_str());
176	    }
177	#endif
178	
179	    // Load plugin library
180	    auto pluginHandles = loadEdgellmPluginLib();
181	
182	    // Parse model config
183	    if (!parseConfig())
184	    {
185	        return false;
186	    }
187	
188	    // Create builder and network
189	    auto [builder, network] = createBuilderAndNetwork();
190	    if (!builder || !network)
191	    {
192	        return false;
193	    }
194	
195	    // Determine ONNX file path
196	    std::string onnxFilePath;
197	    if (mBuilderConfig.maxLoraRank > 0)
198	    {
199	        onnxFilePath = (mOnnxDir / "lora_model.onnx").string();
200	        LOG_INFO("Parsing LoRA-enabled ONNX model: %s", onnxFilePath.c_str());
201	    }
202	    else
203	    {
204	        onnxFilePath = (mOnnxDir / "model.onnx").string();
205	        LOG_INFO("Parsing ONNX model: %s", onnxFilePath.c_str());
206	    }
207	
208	    // Parse ONNX model
209	    auto parser = parseOnnxModel(network.get(), onnxFilePath);
210	    if (!parser)
211	    {
212	        return false;
213	    }
214	
215	    // Print network information
216	    LOG_DEBUG("%s", printNetworkInfo(network.get(), "LLM").c_str());
217	
218	    LOG_DEBUG(
219	        "ONNX parsing complete. mNbKVCacheInputs=%d, mNumLinearAttnLayers=%d", mNbKVCacheInputs, mNumLinearAttnLayers);
220	
221	    // Create builder config
222	    auto config = createBuilderConfig(builder.get());
223	    if (!config)
224	    {
225	        return false;
226	    }
227	
228	    if (mBuilderConfig.profilingDetailed)
229	    {
230	        config->setProfilingVerbosity(nvinfer1::ProfilingVerbosity::kDETAILED);
231	        LOG_INFO("Profiling verbosity set to DETAILED");
232	    }
233	
234	    LOG_DEBUG("Builder config created. Setting up optimization profiles...");
235	
236	    // Setup optimization profiles
237	    if (!setupLLMOptimizationProfiles(*builder.get(), *config.get(), *network.get()))
238	    {
239	        return false;
240	    }
241	
242	    // Create engine directory
243	    if (!std::filesystem::exists(mEngineDir))
244	    {
245	        if (!std::filesystem::create_directories(mEngineDir))
246	        {
247	            LOG_ERROR("Failed to create directory %s", mEngineDir.string().c_str());
248	            return false;
249	        }
250	        LOG_INFO("Created directory %s for saving LLM engine.", mEngineDir.string().c_str());
251	    }
252	
253	    // Determine engine file name
254	    std::string engineFileName;
255	    if (mBuilderConfig.specDraft)
256	    {
257	        engineFileName = "spec_draft.engine";
258	    }
259	    else if (mBuilderConfig.specBase)
260	    {
261	        engineFileName = "spec_base.engine";
262	    }
263	    else
264	    {
265	        engineFileName = "llm.engine";
266	    }
267	
268	    // Build and save engine
269	    std::string const engineFilePath = (mEngineDir / engineFileName).string();
270	    if (!buildAndSerializeEngine(builder.get(), network.get(), config.get(), engineFilePath))
271	    {
272	        return false;
273	    }
274	
275	    // Detect number of deepstack embeds from network (for Qwen3VL models)
276	    mNumDeepstackFeatures = 0;
277	    for (int32_t idx = 0; idx < network->getNbInputs(); idx++)
278	    {
279	        std::string_view const inputName = network->getInput(idx)->getName();
280	        if (inputName.find(binding_names::kDeepstackEmbedsTemplate) != std::string_view::npos)
281	        {
282	            mNumDeepstackFeatures++;
283	        }
284	    }
285	    if (mNumDeepstackFeatures > 0)
286	    {
287	        LOG_INFO("Detected %d deepstack embedding inputs in network (Qwen3VL model)", mNumDeepstackFeatures);
288	    }
289	
290	    // Copy files and save builder config
291	    if (!copyConfig())
292	    {
293	        return false;
294	    }
295	
296	    if (!copyTokenizerFiles())
297	    {
298	        return false;
299	    }
300	
301	    if (!copyEagleFiles())
302	    {
303	        return false;
304	    }
305	
306	    if (!copyVocabMappingFiles())
307	    {
308	        return false;
309	    }
310	
311	    if (!copyEmbeddingFile())
312	    {
313	        return false;
314	    }
315	
316	    if (!copyExternalWeightFiles())
317	    {
318	        return false;
319	    }
320	
321	    return true;
322	}
