324	bool LLMBuilder::parseConfig()
325	{
326	    std::string const jsonPath = (mOnnxDir / "config.json").string();
327	    if (!loadJsonConfig(jsonPath, mModelConfig))
328	    {
329	        return false;
330	    }
331	
332	    // Check model version
333	    std::string modelVersion = mModelConfig.value(binding_names::kEdgellmVersion, "");
334	    version::checkVersion(modelVersion);
335	
336	    std::string const specType = specDecodeType(mModelConfig);
337	    std::string const role = engineRole(mModelConfig);
338	    if (!isValidSpecDecodeType(specType))
339	    {
340	        LOG_ERROR(
341	            "Invalid spec_decode_type='%s'. Expected one of: none, mtp, eagle3, dflash, gemma4_mtp.", specType.c_str());
342	        return false;
343	    }
344	    if (!isValidEngineRole(role))
345	    {
346	        LOG_ERROR("Invalid engine_role='%s'. Expected one of: llm, base, draft.", role.c_str());
347	        return false;
348	    }
349	    if ((role == "llm") != (specType == "none"))
350	    {
351	        LOG_ERROR(
352	            "Invalid config: engine_role='%s' with spec_decode_type='%s'. LLM engines require "
353	            "spec_decode_type=none; speculative base/draft engines require a non-none spec_decode_type.",
354	            role.c_str(), specType.c_str());
355	        return false;
356	    }
357	    if ((mBuilderConfig.specDraft && role != "draft") || (mBuilderConfig.specBase && role != "base")
358	        || (!mBuilderConfig.specDraft && !mBuilderConfig.specBase && role != "llm"))
359	    {
360	        LOG_ERROR(
361	            "Build mode does not match config: engine_role='%s' (use --specBase for base, --specDraft for "
362	            "draft, and neither flag for vanilla LLM).",
363	            role.c_str());
364	        return false;
365	    }
366	
367	    mHiddenSize = mModelConfig["hidden_size"].get<int32_t>();
368	    // For MTP draft, base model outputs hidden_size (1x); for EAGLE3 draft, it outputs hidden_size * 3.
369	    if (isSpecDecodeDraft(mModelConfig, "mtp"))
370	    {
371	        mTargetModelOutputHiddenDim = mHiddenSize;
372	    }
373	    else if ((isSpecDecodeDraft(mModelConfig, "dflash") || isSpecDecodeDraft(mModelConfig, "gemma4_mtp"))
374	        && mModelConfig.contains("base_model_hidden_size"))
375	    {
376	        mTargetModelOutputHiddenDim = mModelConfig["base_model_hidden_size"].get<int32_t>();
377	    }
378	    else
379	    {
380	        mTargetModelOutputHiddenDim = mHiddenSize * 3;
381	    }
382	    mNumKVHeads = mModelConfig["num_key_value_heads"].get<int32_t>();
383	    auto numAttentionHeads = mModelConfig["num_attention_heads"].get<int32_t>();
384	
385	    if (mModelConfig.contains("head_dim"))
386	    {
387	        mHeadSize = mModelConfig["head_dim"].get<int32_t>();
388	    }
389	    else
390	    {
391	        mHeadSize = mHiddenSize / numAttentionHeads;
392	    }
393	
394	    mNumLinearAttnLayers = mModelConfig.value("num_linear_attn_layers", 0);
395	    mRecurrentStateNumHeads = mModelConfig.value("recurrent_state_num_heads", 0);
396	    mRecurrentStateHeadDim = mModelConfig.value("recurrent_state_head_dim", 0);
397	    mRecurrentStateSize = mModelConfig.value("recurrent_state_size", 0);
398	    mConvDim = mModelConfig.value("conv_dim", 0);
399	    mConvKernel = mModelConfig.value("conv_kernel", 0);
400	
401	    if (mModelConfig.contains("kv_layer_configs") && mModelConfig["kv_layer_configs"].is_array())
402	    {
403	        mNbKVCacheInputs = 0;
404	        for (auto const& layerConfig : mModelConfig["kv_layer_configs"])
405	        {
406	            if (layerConfig.is_object())
407	            {
408	                ++mNbKVCacheInputs;
409	            }
410	        }
411	    }
412	    else if (mNumLinearAttnLayers > 0)
413	    {
414	        // For hybrid models, only attention layers have KV caches.
415	        mNbKVCacheInputs = mModelConfig.value("num_attention_layers", mModelConfig["num_hidden_layers"].get<int32_t>());
416	    }
417	    else
418	    {
419	        mNbKVCacheInputs = mModelConfig["num_hidden_layers"].get<int32_t>();
420	    }
421	
422	    mRotaryDim = getRotaryDim(mModelConfig, mHeadSize);
423	    mSlidingRotaryDim = mRotaryDim;
424	    mFullRotaryDim = mRotaryDim;
425	    if (mModelConfig.contains("sliding_rope_config") && mModelConfig["sliding_rope_config"].is_object())
426	    {
427	        mSlidingRotaryDim = getRotaryDim(mModelConfig["sliding_rope_config"], mHeadSize);
428	    }
429	    if (mModelConfig.contains("full_rope_config") && mModelConfig["full_rope_config"].is_object())
430	    {
431	        int64_t const fullHeadDim = mModelConfig.value("global_head_dim", static_cast<int64_t>(mHeadSize));
432	        mFullRotaryDim = getRotaryDim(mModelConfig["full_rope_config"], fullHeadDim);
433	    }
434	
435	    mNumLinearAttnLayers = mModelConfig.value("num_linear_attn_layers", 0);
436	    mRecurrentStateNumHeads = mModelConfig.value("recurrent_state_num_heads", 0);
437	    mRecurrentStateHeadDim = mModelConfig.value("recurrent_state_head_dim", 0);
438	    mRecurrentStateSize = mModelConfig.value("recurrent_state_size", 0);
439	    mConvDim = mModelConfig.value("conv_dim", 0);
440	    mConvKernel = mModelConfig.value("conv_kernel", 0);
441	
442	    // For hybrid models, only attention layers have KV caches
443	    if (mNumLinearAttnLayers > 0)
444	    {
445	        mNbKVCacheInputs = mModelConfig.value("num_attention_layers", mModelConfig["num_hidden_layers"].get<int32_t>());
446	    }
447	    else
448	    {
449	        mNbKVCacheInputs = mModelConfig["num_hidden_layers"].get<int32_t>();
450	    }
451	
452	    // Build per-layer head size vector for heterogeneous models (e.g. Gemma4).
453	    // Prefer kv_layer_configs (authoritative per-layer dims) when available;
454	    // fall back to global_head_dim + layer_types for older exports.
455	    int64_t globalHeadSize = mModelConfig.value("global_head_dim", static_cast<int64_t>(0));
456	    if (mModelConfig.contains("kv_layer_configs") && !mModelConfig["kv_layer_configs"].is_null())
457	    {
458	        auto const& kvLayerConfigs = mModelConfig["kv_layer_configs"];
459	        check::check(static_cast<int>(kvLayerConfigs.size()) >= mNbKVCacheInputs,
460	            "kv_layer_configs has fewer entries than expected KV cache layers");
461	        for (int i = 0; i < mNbKVCacheInputs; ++i)
462	        {
463	            auto const& lc = kvLayerConfigs[i];
464	            int64_t layerHeadDim
465	                = (lc.is_null() || !lc.contains("head_dim")) ? mHeadSize : lc["head_dim"].get<int64_t>();
466	            mPerLayerHeadSize.push_back(layerHeadDim);
467	            int64_t layerNumKVHeads
468	                = (lc.is_null() || !lc.contains("num_kv_heads")) ? mNumKVHeads : lc["num_kv_heads"].get<int64_t>();
469	            mPerLayerNumKVHeads.push_back(layerNumKVHeads);
470	        }
471	        LOG_INFO("Heterogeneous head sizes from kv_layer_configs: %d layers", mNbKVCacheInputs);
472	    }
473	    else if (globalHeadSize > 0 && globalHeadSize != mHeadSize && mModelConfig.contains("layer_types"))
474	    {
475	        auto const& layerTypes = mModelConfig["layer_types"];
476	        for (int i = 0; i < mNbKVCacheInputs; ++i)
477	        {
478	            std::string lt = (i < static_cast<int>(layerTypes.size())) ? layerTypes[i].get<std::string>() : "";
479	            mPerLayerHeadSize.push_back((lt == "full_attention") ? globalHeadSize : mHeadSize);
480	        }
481	        LOG_INFO("Heterogeneous head sizes: %d layers with head_dim=%ld, %ld layers with global_head_dim=%ld",
482	            mNbKVCacheInputs, mHeadSize, std::count(mPerLayerHeadSize.begin(), mPerLayerHeadSize.end(), globalHeadSize),
483	            globalHeadSize);
484	    }
485	
486	    return true;
487	}
