489	bool LLMBuilder::setupLLMOptimizationProfiles(
490	    nvinfer1::IBuilder& builder, nvinfer1::IBuilderConfig& config, nvinfer1::INetworkDefinition const& network)
491	{
492	    auto* contextProfile = builder.createOptimizationProfile();
493	    auto* generationProfile = builder.createOptimizationProfile();
494	
495	    bool result = true;
496	
497	    if (isSpecDecodeDraft(mModelConfig, "dflash"))
498	    {
499	        result &= setupDFlashDraftProfiles(*contextProfile, *generationProfile);
500	        if (!result)
501	        {
502	            LOG_ERROR("Failed to setup DFlash draft optimization profiles");
503	            return false;
504	        }
505	        LOG_DEBUG("%s", printOptimizationProfile(contextProfile, "context_profile", &network).c_str());
506	        LOG_DEBUG("%s", printOptimizationProfile(generationProfile, "generation_profile", &network).c_str());
507	        config.addOptimizationProfile(contextProfile);
508	        config.addOptimizationProfile(generationProfile);
509	        return true;
510	    }
511	
512	    if (isSpecDecodeDraft(mModelConfig, "gemma4_mtp"))
513	    {
514	        result &= setupGemma4MTPDraftProfiles(*contextProfile, *generationProfile, network);
515	        if (!result)
516	        {
517	            LOG_ERROR("Failed to setup Gemma4 MTP draft optimization profiles");
518	            return false;
519	        }
520	        LOG_DEBUG("%s", printOptimizationProfile(contextProfile, "context_profile", &network).c_str());
521	        LOG_DEBUG("%s", printOptimizationProfile(generationProfile, "generation_profile", &network).c_str());
522	        config.addOptimizationProfile(contextProfile);
523	        config.addOptimizationProfile(generationProfile);
524	        return true;
525	    }
526	
527	    // Setup common profiles
528	    result &= setupCommonProfiles(*contextProfile, *generationProfile);
529	    result &= setupRopeProfiles(*contextProfile, *generationProfile, network);
530	
531	    // Setup model-specific profiles
532	    if (mBuilderConfig.specBase || mBuilderConfig.specDraft)
533	    {
534	        result &= setupSpecDecodeProfiles(*contextProfile, *generationProfile);
535	    }
536	    else
537	    {
538	        result &= setupVanillaProfiles(*contextProfile, *generationProfile);
539	    }
540	
541	    // Setup hybrid state profiles for MTP/DFlash base models.
542	    if (isSpecDecodeBase(mModelConfig, "mtp") || isSpecDecodeBase(mModelConfig, "dflash"))
543	    {
544	        result &= setupIntermediateRecurrentStateProfiles(*contextProfile, *generationProfile);
545	        result &= setupIntermediateConvStateProfiles(*contextProfile, *generationProfile);
546	        result &= setupLinearAttentionSpecVerifyProfiles(*contextProfile, *generationProfile, network);
547	    }
548	
549	    // Setup Gemma4 PLE profiles when ple_token_embeds_* inputs are present.
550	    result &= setupPleProfiles(*contextProfile, *generationProfile, network);
551	
552	    // Setup Deepstack profiles for Qwen3VL models
553	    result &= setupDeepstackProfiles(*contextProfile, *generationProfile, network);
554	
555	    // Setup lm_head_weight profile for CodePredictor (Qwen3-Omni)
556	    result &= setupLmHeadWeightProfiles(*contextProfile, *generationProfile, network);
557	
558	    if (mBuilderConfig.maxLoraRank > 0)
559	    {
560	        result &= setupLoraProfiles(*contextProfile, *generationProfile, network);
561	    }
562	
563	    if (!result)
564	    {
565	        LOG_ERROR("Failed to setup optimization profiles");
566	        return false;
567	    }
568	
569	    LOG_DEBUG("%s", printOptimizationProfile(contextProfile, "context_profile", &network).c_str());
570	    LOG_DEBUG("%s", printOptimizationProfile(generationProfile, "generation_profile", &network).c_str());
571	
572	    config.addOptimizationProfile(contextProfile);
573	    config.addOptimizationProfile(generationProfile);
574	
575	    return true;
576	}
