578	bool LLMBuilder::setupCommonProfiles(
579	    nvinfer1::IOptimizationProfile& contextProfile, nvinfer1::IOptimizationProfile& generationProfile)
580	{
581	    bool result = true;
582	
583	    // Context lengths
584	    result &= setOptimizationProfile(&contextProfile, binding_names::kContextLengths, createDims({1}),
585	        createDims({mBuilderConfig.maxBatchSize}), createDims({mBuilderConfig.maxBatchSize}));
586	    result &= setOptimizationProfile(&generationProfile, binding_names::kContextLengths, createDims({1}),
587	        createDims({mBuilderConfig.maxBatchSize}), createDims({mBuilderConfig.maxBatchSize}));
588	
589	    // For KVCacheStartIndex, we use zero shape to indicate the kvcache is empty for all sequences in the batch.
590	    // This can help distinguish the normal prefill and chunked prefill execution.
591	    result &= setOptimizationProfile(&contextProfile, binding_names::kKVCacheStartIndex, createDims({0}),
592	        createDims({mBuilderConfig.maxBatchSize}), createDims({mBuilderConfig.maxBatchSize}));
593	    result &= setOptimizationProfile(&generationProfile, binding_names::kKVCacheStartIndex, createDims({1}),
594	        createDims({mBuilderConfig.maxBatchSize}), createDims({mBuilderConfig.maxBatchSize}));
595	
596	    // KV cache profiles
597	    LOG_DEBUG("Setting up KV cache profiles for %d layers...", mNbKVCacheInputs);
598	    result &= setupKVCacheProfiles(contextProfile, generationProfile);
599	    LOG_DEBUG("KV cache profiles done. Setting up recurrent state profiles for %d layers...", mNumLinearAttnLayers);
600	
601	    // Recurrent state profiles for hybrid layers
602	    result &= setupRecurrentStateProfiles(&contextProfile, &generationProfile);
603	
604	    LOG_DEBUG("Recurrent state profiles done. Setting up Conv state profiles...");
605	    // Conv state profiles for recurrent causal conv1d layers
606	    result &= setupConvStateProfiles(&contextProfile, &generationProfile);
607	    LOG_DEBUG("Conv state profiles done.");
608	
609	    return result;
610	}
