612	bool LLMBuilder::setupRopeProfiles(nvinfer1::IOptimizationProfile& contextProfile,
613	    nvinfer1::IOptimizationProfile& generationProfile, nvinfer1::INetworkDefinition const& network)
614	{
615	    bool result = true;
616	    auto setRopeProfile = [&](char const* bindingName, int64_t rotaryDim) {
617	        result &= setOptimizationProfile(&contextProfile, bindingName,
618	            createDims({1, mBuilderConfig.maxKVCacheCapacity, rotaryDim}),
619	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxKVCacheCapacity, rotaryDim}),
620	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxKVCacheCapacity, rotaryDim}));
621	        result &= setOptimizationProfile(&generationProfile, bindingName,
622	            createDims({1, mBuilderConfig.maxKVCacheCapacity, rotaryDim}),
623	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxKVCacheCapacity, rotaryDim}),
624	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxKVCacheCapacity, rotaryDim}));
625	    };
626	
627	    // RoPE rotary cos/sin inputs: single binding for single-RoPE engines, or
628	    // explicit sliding/full bindings for mixed-attention engines.
629	    if (hasInputBinding(network, binding_names::kRopeCosSinSliding))
630	    {
631	        setRopeProfile(binding_names::kRopeCosSinSliding, mSlidingRotaryDim);
632	    }
633	    if (hasInputBinding(network, binding_names::kRopeCosSinFull))
634	    {
635	        setRopeProfile(binding_names::kRopeCosSinFull, mFullRotaryDim);
636	    }
637	    if (hasInputBinding(network, binding_names::kRopeCosSin))
638	    {
639	        setRopeProfile(binding_names::kRopeCosSin, mRotaryDim);
640	    }
641	
642	    return result;
643	}
