645	bool LLMBuilder::setupVanillaProfiles(
646	    nvinfer1::IOptimizationProfile& contextProfile, nvinfer1::IOptimizationProfile& generationProfile)
647	{
648	    bool result = true;
649	
650	    // Input embeddings - always dynamic
651	    result &= setOptimizationProfile(&contextProfile, binding_names::kInputsEmbeds, createDims({1, 1, mHiddenSize}),
652	        createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxInputLen / 2, mHiddenSize}),
653	        createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxInputLen, mHiddenSize}));
654	    result &= setOptimizationProfile(&generationProfile, binding_names::kInputsEmbeds, createDims({1, 1, mHiddenSize}),
655	        createDims({mBuilderConfig.maxBatchSize, 1, mHiddenSize}),
656	        createDims({mBuilderConfig.maxBatchSize, 1, mHiddenSize}));
657	
658	    if (mModelConfig.value("use_vision_bidirectional_attention", false))
659	    {
660	        result &= setOptimizationProfile(&contextProfile, binding_names::kVisionBlockIds, createDims({1, 1}),
661	            createDims({mBuilderConfig.maxBatchSize, std::max<int64_t>(1, mBuilderConfig.maxInputLen / 2)}),
662	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxInputLen}));
663	        // Decode ignores block IDs, but the static engine binding remains present.
664	        result &= setOptimizationProfile(&generationProfile, binding_names::kVisionBlockIds, createDims({1, 1}),
665	            createDims({mBuilderConfig.maxBatchSize, 1}), createDims({mBuilderConfig.maxBatchSize, 1}));
666	    }
667	
668	    // Last token IDs
669	    result &= setOptimizationProfile(&contextProfile, binding_names::kLastTokenIds, createDims({1, 1}),
670	        createDims({mBuilderConfig.maxBatchSize, 1}), createDims({mBuilderConfig.maxBatchSize, 1}));
671	    result &= setOptimizationProfile(&generationProfile, binding_names::kLastTokenIds, createDims({1, 1}),
672	        createDims({mBuilderConfig.maxBatchSize, 1}), createDims({mBuilderConfig.maxBatchSize, 1}));
673	
674	    return result;
