677	bool LLMBuilder::setupSpecDecodeProfiles(
678	    nvinfer1::IOptimizationProfile& contextProfile, nvinfer1::IOptimizationProfile& generationProfile)
679	{
680	    bool result = true;
681	
682	    int const maxTokens = mBuilderConfig.specDraft ? mBuilderConfig.maxDraftTreeSize : mBuilderConfig.maxVerifyTreeSize;
683	
684	    // Input embeddings
685	    result &= setOptimizationProfile(&contextProfile, binding_names::kInputsEmbeds, createDims({1, 1, mHiddenSize}),
686	        createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxInputLen / 2, mHiddenSize}),
687	        createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxInputLen, mHiddenSize}));
688	    result &= setOptimizationProfile(&generationProfile, binding_names::kInputsEmbeds, createDims({1, 1, mHiddenSize}),
689	        createDims({mBuilderConfig.maxBatchSize, maxTokens / 2, mHiddenSize}),
690	        createDims({mBuilderConfig.maxBatchSize, maxTokens, mHiddenSize}));
691	
692	    // Last token IDs - 2D shape [batch_size, num_selected_tokens]
693	    result &= setOptimizationProfile(&contextProfile, binding_names::kLastTokenIds, createDims({1, 1}),
694	        createDims({mBuilderConfig.maxBatchSize, 1}), createDims({mBuilderConfig.maxBatchSize, 1}));
695	    result &= setOptimizationProfile(&generationProfile, binding_names::kLastTokenIds, createDims({1, 1}),
696	        createDims({mBuilderConfig.maxBatchSize, maxTokens / 2}), createDims({mBuilderConfig.maxBatchSize, maxTokens}));
697	
698	    if (mBuilderConfig.specDraft)
699	    {
700	        // Hidden states from draft
701	        result &= setOptimizationProfile(&contextProfile, binding_names::kDraftModelHiddenStates,
702	            createDims({1, 1, mHiddenSize}),
703	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxInputLen / 2, mHiddenSize}),
704	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxInputLen, mHiddenSize}));
705	        result &= setOptimizationProfile(&generationProfile, binding_names::kDraftModelHiddenStates,
706	            createDims({1, 1, mHiddenSize}), createDims({mBuilderConfig.maxBatchSize, maxTokens / 2, mHiddenSize}),
707	            createDims({mBuilderConfig.maxBatchSize, maxTokens, mHiddenSize}));
708	
709	        // Hidden states input
710	        result &= setOptimizationProfile(&contextProfile, binding_names::kBaseModelHiddenStates,
711	            createDims({1, 1, mTargetModelOutputHiddenDim}),
712	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxInputLen / 2, mTargetModelOutputHiddenDim}),
713	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxInputLen, mTargetModelOutputHiddenDim}));
714	        result &= setOptimizationProfile(&generationProfile, binding_names::kBaseModelHiddenStates,
715	            createDims({1, 1, mTargetModelOutputHiddenDim}),
716	            createDims({mBuilderConfig.maxBatchSize, maxTokens / 2, mTargetModelOutputHiddenDim}),
717	            createDims({mBuilderConfig.maxBatchSize, maxTokens, mTargetModelOutputHiddenDim}));
718	    }
719	
720	    // Attention mask and position ID
721	    if (mBuilderConfig.specDraft || mBuilderConfig.specBase)
722	    {
723	        int32_t const attnMaskAlignSize = 32;
724	        result &= setOptimizationProfile(&contextProfile, binding_names::kAttentionMask, createDims({1, 1, 1}),
725	            createDims({mBuilderConfig.maxBatchSize, 1, 1}), createDims({mBuilderConfig.maxBatchSize, 1, 1}));
726	        result &= setOptimizationProfile(&generationProfile, binding_names::kAttentionMask, createDims({1, 1, 1}),
727	            createDims({mBuilderConfig.maxBatchSize, maxTokens / 2,
728	                static_cast<int64_t>(divUp(maxTokens / 2, attnMaskAlignSize) * attnMaskAlignSize)}),
729	            createDims({mBuilderConfig.maxBatchSize, maxTokens,
730	                static_cast<int64_t>(divUp(maxTokens, attnMaskAlignSize) * attnMaskAlignSize)}));
731	
732	        result &= setOptimizationProfile(&contextProfile, binding_names::kAttentionPosId, createDims({1, 1}),
733	            createDims({mBuilderConfig.maxBatchSize, 1}), createDims({mBuilderConfig.maxBatchSize, 1}));
734	        result &= setOptimizationProfile(&generationProfile, binding_names::kAttentionPosId, createDims({1, 1}),
735	            createDims({mBuilderConfig.maxBatchSize, maxTokens / 2}),
736	            createDims({mBuilderConfig.maxBatchSize, maxTokens}));
737	    }
738	
739	    return result;
740	}
