742	bool LLMBuilder::setupDFlashDraftProfiles(
743	    nvinfer1::IOptimizationProfile& contextProfile, nvinfer1::IOptimizationProfile& generationProfile)
744	{
745	    bool result = true;
746	
747	    int64_t const maxDraftTokens = std::max<int64_t>(1, mBuilderConfig.maxDraftTreeSize);
748	    int64_t const optDraftTokens = maxDraftTokens;
749	    int64_t const maxPrefillTargetHiddenLen = std::max<int64_t>(1, mBuilderConfig.maxInputLen);
750	    int64_t const optPrefillTargetHiddenLen = std::max<int64_t>(1, maxPrefillTargetHiddenLen / 2);
751	    int64_t const maxDecodeTargetHiddenLen = maxDraftTokens;
752	    int64_t const optDecodeTargetHiddenLen = maxDraftTokens;
753	
754	    int64_t const packedMaskLen = static_cast<int64_t>(divUp(maxDraftTokens, 32));
755	    int64_t const optPackedMaskLen = static_cast<int64_t>(divUp(optDraftTokens, 32));
756	
757	    // Profile 0 handles round-0/system-prompt cache update, where target hidden spans the prompt.
758	    // Profile 1 handles steady-state block proposal, where target hidden delta is bounded by block size.
759	    auto setupOneProfile = [&](nvinfer1::IOptimizationProfile& profile, int64_t optTargetHiddenLen,
760	                               int64_t maxTargetHiddenLen) {
761	        bool ok = true;
762	        // inputs_embeds: [batch, block_seq, hiddenSize]
763	        ok &= setOptimizationProfile(&profile, binding_names::kInputsEmbeds, createDims({1, 1, mHiddenSize}),
764	            createDims({mBuilderConfig.maxBatchSize, optDraftTokens, mHiddenSize}),
765	            createDims({mBuilderConfig.maxBatchSize, maxDraftTokens, mHiddenSize}));
766	        // dflash_target_hidden_concat: [batch, delta_seq, baseOutputHiddenDim]
767	        ok &= setOptimizationProfile(&profile, binding_names::kDFlashTargetHiddenConcat,
768	            createDims({1, 1, mTargetModelOutputHiddenDim}),
769	            createDims({mBuilderConfig.maxBatchSize, optTargetHiddenLen, mTargetModelOutputHiddenDim}),
770	            createDims({mBuilderConfig.maxBatchSize, maxTargetHiddenLen, mTargetModelOutputHiddenDim}));
771	        // rope_rotary_cos_sin: [1, kv_capacity, rotaryDim]
772	        ok &= setOptimizationProfile(&profile, binding_names::kRopeCosSin, createDims({1, 1, mRotaryDim}),
773	            createDims({1, mBuilderConfig.maxKVCacheCapacity, mRotaryDim}),
774	            createDims({1, mBuilderConfig.maxKVCacheCapacity, mRotaryDim}));
775	        // context_lengths: [batch]
776	        ok &= setOptimizationProfile(&profile, binding_names::kContextLengths, createDims({1}),
777	            createDims({mBuilderConfig.maxBatchSize}), createDims({mBuilderConfig.maxBatchSize}));
778	        // kvcache_start_index: [batch]
779	        ok &= setOptimizationProfile(&profile, binding_names::kKVCacheStartIndex, createDims({1}),
780	            createDims({mBuilderConfig.maxBatchSize}), createDims({mBuilderConfig.maxBatchSize}));
781	        // dflash_delta_lengths: [batch]
782	        ok &= setOptimizationProfile(&profile, binding_names::kDFlashDeltaLengths, createDims({1}),
783	            createDims({mBuilderConfig.maxBatchSize}), createDims({mBuilderConfig.maxBatchSize}));
784	        // attention_mask: [batch, block_seq, packed_mask_len]
785	        ok &= setOptimizationProfile(&profile, binding_names::kAttentionMask, createDims({1, 1, 1}),
786	            createDims({mBuilderConfig.maxBatchSize, optDraftTokens, optPackedMaskLen}),
787	            createDims({mBuilderConfig.maxBatchSize, maxDraftTokens, packedMaskLen}));
788	        // attention_pos_id: [batch, block_seq]
789	        ok &= setOptimizationProfile(&profile, binding_names::kAttentionPosId, createDims({1, 1}),
790	            createDims({mBuilderConfig.maxBatchSize, optDraftTokens}),
791	            createDims({mBuilderConfig.maxBatchSize, maxDraftTokens}));
792	        // KV cache per-layer: [batch, 2, numKVHeads, kv_capacity, headDim]
793	        for (int32_t i = 0; i < mNbKVCacheInputs; ++i)
794	        {
795	            int64_t layerHeadSize = (!mPerLayerHeadSize.empty()) ? mPerLayerHeadSize[i] : mHeadSize;
796	            int64_t layerNumKVHeads = (!mPerLayerNumKVHeads.empty()) ? mPerLayerNumKVHeads[i] : mNumKVHeads;
797	            std::string pastName = std::string(binding_names::kPastKeyValuesTemplate) + "_" + std::to_string(i);
798	            std::string presentName = std::string(binding_names::kPresentKeyValuesTemplate) + "_" + std::to_string(i);
799	            ok &= setOptimizationProfile(&profile, pastName.c_str(),
800	                createDims({1, 2, layerNumKVHeads, 1, layerHeadSize}),
801	                createDims({mBuilderConfig.maxBatchSize, 2, layerNumKVHeads, mBuilderConfig.maxKVCacheCapacity,
802	                    layerHeadSize}),
803	                createDims({mBuilderConfig.maxBatchSize, 2, layerNumKVHeads, mBuilderConfig.maxKVCacheCapacity,
804	                    layerHeadSize}));
805	            ok &= setOptimizationProfile(&profile, presentName.c_str(),
806	                createDims({1, 2, layerNumKVHeads, 1, layerHeadSize}),
807	                createDims({mBuilderConfig.maxBatchSize, 2, layerNumKVHeads, mBuilderConfig.maxKVCacheCapacity,
808	                    layerHeadSize}),
809	                createDims({mBuilderConfig.maxBatchSize, 2, layerNumKVHeads, mBuilderConfig.maxKVCacheCapacity,
810	                    layerHeadSize}));
811	        }
812	        return ok;
813	    };
814	
815	    result &= setupOneProfile(contextProfile, optPrefillTargetHiddenLen, maxPrefillTargetHiddenLen);
816	    result &= setupOneProfile(generationProfile, optDecodeTargetHiddenLen, maxDecodeTargetHiddenLen);
817	    return result;
818	}
