820	bool LLMBuilder::setupGemma4MTPDraftProfiles(nvinfer1::IOptimizationProfile& contextProfile,
821	    nvinfer1::IOptimizationProfile& generationProfile, nvinfer1::INetworkDefinition const& network)
822	{
823	    bool result = true;
824	    int64_t const baseHiddenSize = mTargetModelOutputHiddenDim;
825	
826	    auto setupRopeProfile = [&](nvinfer1::IOptimizationProfile& profile, char const* bindingName, int64_t rotaryDim) {
827	        return setOptimizationProfile(&profile, bindingName,
828	            createDims({1, mBuilderConfig.maxKVCacheCapacity, rotaryDim}),
829	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxKVCacheCapacity, rotaryDim}),
830	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxKVCacheCapacity, rotaryDim}));
831	    };
832	
833	    auto setupOneProfile = [&](nvinfer1::IOptimizationProfile& profile) {
834	        bool ok = true;
835	        ok &= setOptimizationProfile(&profile, binding_names::kInputsEmbeds, createDims({1, 1, baseHiddenSize}),
836	            createDims({mBuilderConfig.maxBatchSize, 1, baseHiddenSize}),
837	            createDims({mBuilderConfig.maxBatchSize, 1, baseHiddenSize}));
838	        ok &= setOptimizationProfile(&profile, binding_names::kBaseModelHiddenStates,
839	            createDims({1, 1, baseHiddenSize}), createDims({mBuilderConfig.maxBatchSize, 1, baseHiddenSize}),
840	            createDims({mBuilderConfig.maxBatchSize, 1, baseHiddenSize}));
841	        ok &= setOptimizationProfile(&profile, binding_names::kContextLengths, createDims({1}),
842	            createDims({mBuilderConfig.maxBatchSize}), createDims({mBuilderConfig.maxBatchSize}));
843	
844	        if (auto const rotaryDim = getStaticInputDim(network, binding_names::kRopeCosSinSliding, 2))
845	        {
846	            ok &= setupRopeProfile(profile, binding_names::kRopeCosSinSliding, *rotaryDim);
847	        }
848	        if (auto const rotaryDim = getStaticInputDim(network, binding_names::kRopeCosSinFull, 2))
849	        {
850	            ok &= setupRopeProfile(profile, binding_names::kRopeCosSinFull, *rotaryDim);
851	        }
852	        if (auto const rotaryDim = getStaticInputDim(network, binding_names::kRopeCosSin, 2))
853	        {
854	            ok &= setupRopeProfile(profile, binding_names::kRopeCosSin, *rotaryDim);
855	        }
856	
857	        for (int i = 0; i < mNbKVCacheInputs; ++i)
858	        {
859	            int64_t const layerHeadSize = (!mPerLayerHeadSize.empty()) ? mPerLayerHeadSize[i] : mHeadSize;
860	            int64_t const layerNumKVHeads = (!mPerLayerNumKVHeads.empty()) ? mPerLayerNumKVHeads[i] : mNumKVHeads;
861	            nvinfer1::Dims const minKVCacheShape = createDims({1, 2, layerNumKVHeads, 1, layerHeadSize});
862	            nvinfer1::Dims const optKVCacheShape = createDims(
863	                {mBuilderConfig.maxBatchSize, 2, layerNumKVHeads, mBuilderConfig.maxKVCacheCapacity, layerHeadSize});
864	            nvinfer1::Dims const maxKVCacheShape = optKVCacheShape;
865	            ok &= setOptimizationProfile(&profile, binding_names::formatKVCacheName(i, true).c_str(), minKVCacheShape,
866	                optKVCacheShape, maxKVCacheShape);
867	        }
868	
869	        return ok;
870	    };
871	
872	    result &= setupOneProfile(contextProfile);
873	    result &= setupOneProfile(generationProfile);
874	    return result;
875	}
