877	bool LLMBuilder::setupPleProfiles(nvinfer1::IOptimizationProfile& contextProfile,
878	    nvinfer1::IOptimizationProfile& generationProfile, nvinfer1::INetworkDefinition const& network)
879	{
880	    bool result = true;
881	    bool foundPleInput = false;
882	    std::string_view const prefix = binding_names::kPleTokenEmbedsTemplate;
883	
884	    for (int32_t idx = 0; idx < network.getNbInputs(); ++idx)
885	    {
886	        auto const* input = network.getInput(idx);
887	        char const* const inputName = input->getName();
888	        std::string_view const inputNameView = inputName;
889	        if (inputNameView.rfind(prefix, 0) != 0 || inputNameView.size() <= prefix.size()
890	            || inputNameView[prefix.size()] != '_')
891	        {
892	            continue;
893	        }
894	        foundPleInput = true;
895	
896	        auto const inputDims = input->getDimensions();
897	        if (inputDims.nbDims != 3 || inputDims.d[2] <= 0)
898	        {
899	            LOG_ERROR("PLE input %s must be rank-3 [batch, seq_len, hidden] with static hidden dimension.", inputName);
900	            result = false;
901	            continue;
902	        }
903	
904	        int64_t const pleHiddenSize = inputDims.d[2];
905	        result &= setOptimizationProfile(&contextProfile, inputName, createDims({1, 1, pleHiddenSize}),
906	            createDims(
907	                {mBuilderConfig.maxBatchSize, std::max<int64_t>(1, mBuilderConfig.maxInputLen / 2), pleHiddenSize}),
908	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxInputLen, pleHiddenSize}));
909	
910	        if (mBuilderConfig.specBase || mBuilderConfig.specDraft)
911	        {
912	            int64_t const maxTokens
913	                = mBuilderConfig.specDraft ? mBuilderConfig.maxDraftTreeSize : mBuilderConfig.maxVerifyTreeSize;
914	            result &= setOptimizationProfile(&generationProfile, inputName, createDims({1, 1, pleHiddenSize}),
915	                createDims({mBuilderConfig.maxBatchSize, std::max<int64_t>(1, maxTokens / 2), pleHiddenSize}),
916	                createDims({mBuilderConfig.maxBatchSize, maxTokens, pleHiddenSize}));
917	        }
918	        else
919	        {
920	            result &= setOptimizationProfile(&generationProfile, inputName, createDims({1, 1, pleHiddenSize}),
921	                createDims({mBuilderConfig.maxBatchSize, 1, pleHiddenSize}),
922	                createDims({mBuilderConfig.maxBatchSize, 1, pleHiddenSize}));
923	        }
924	    }
925	
926	    if (foundPleInput)
927	    {
928	        LOG_INFO("Configured optimization profiles for Gemma4 PLE inputs.");
929	    }
930	    if (!result)
931	    {
932	        LOG_ERROR("Failed to setup optimization profiles at setupPleProfiles().");
933	    }
934	    return result;
935	}
