937	bool LLMBuilder::setupDeepstackProfiles(nvinfer1::IOptimizationProfile& contextProfile,
938	    nvinfer1::IOptimizationProfile& generationProfile, nvinfer1::INetworkDefinition const& network)
939	{
940	    bool result = true;
941	
942	    // Dynamically detect all deepstack_embeds inputs in the network
943	    std::vector<std::string> deepstackInputs;
944	    for (int32_t idx = 0; idx < network.getNbInputs(); idx++)
945	    {
946	        std::string_view const inputName = network.getInput(idx)->getName();
947	        if (inputName.find(binding_names::kDeepstackEmbedsTemplate) != std::string_view::npos)
948	        {
949	            deepstackInputs.emplace_back(inputName);
950	        }
951	    }
952	
953	    // If no deepstack embeds found, return early (not a Qwen3VL model)
954	    if (deepstackInputs.empty())
955	    {
956	        return true;
957	    }
958	
959	    LOG_INFO("Detected %zu deepstack embedding inputs", deepstackInputs.size());
960	
961	    // Setup profiles for all detected deepstack_embeds inputs
962	    // These have the same shape as inputs_embeds: [batch_size, seq_len, hidden_size]
963	    for (auto const& deepstackInputName : deepstackInputs)
964	    {
965	        LOG_INFO("Setting up optimization profile for %s", deepstackInputName.c_str());
966	
967	        // Same profile as inputs_embeds
968	        result &= setOptimizationProfile(&contextProfile, deepstackInputName.c_str(), createDims({1, 1, mHiddenSize}),
969	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxInputLen / 2, mHiddenSize}),
970	            createDims({mBuilderConfig.maxBatchSize, mBuilderConfig.maxInputLen, mHiddenSize}));
971	
972	        if (mBuilderConfig.specBase || mBuilderConfig.specDraft)
973	        {
974	            int const maxTokens
975	                = mBuilderConfig.specDraft ? mBuilderConfig.maxDraftTreeSize : mBuilderConfig.maxVerifyTreeSize;
976	            result &= setOptimizationProfile(&generationProfile, deepstackInputName.c_str(),
977	                createDims({1, 1, mHiddenSize}), createDims({mBuilderConfig.maxBatchSize, maxTokens / 2, mHiddenSize}),
978	                createDims({mBuilderConfig.maxBatchSize, maxTokens, mHiddenSize}));
979	        }
980	        else
981	        {
982	            result &= setOptimizationProfile(&generationProfile, deepstackInputName.c_str(),
983	                createDims({1, 1, mHiddenSize}), createDims({mBuilderConfig.maxBatchSize, 1, mHiddenSize}),
984	                createDims({mBuilderConfig.maxBatchSize, 1, mHiddenSize}));
985	        }
986	    }
987	
988	    if (!result)
989	    {
990	        LOG_ERROR("Failed to setup optimization profiles at setupDeepstackProfiles().");
991	    }
992	
993	    return result;
994	}
