996	bool LLMBuilder::setupLmHeadWeightProfiles(nvinfer1::IOptimizationProfile& contextProfile,
997	    nvinfer1::IOptimizationProfile& generationProfile, nvinfer1::INetworkDefinition const& network)
998	{
999	    bool result = true;
1000	
1001	    // Detect if lm_head_weight input exists (CodePredictor model)
1002	    bool hasLmHeadWeight = false;
1003	    for (int32_t idx = 0; idx < network.getNbInputs(); idx++)
1004	    {
1005	        std::string_view const inputName = network.getInput(idx)->getName();
1006	        if (inputName == binding_names::kLmHeadWeight)
1007	        {
1008	            hasLmHeadWeight = true;
1009	            break;
1010	        }
1011	    }
1012	
1013	    // If no lm_head_weight input found, return early (not a CodePredictor model)
1014	    if (!hasLmHeadWeight)
1015	    {
1016	        return true;
1017	    }
1018	
1019	    LOG_INFO("Detected lm_head_weight input (CodePredictor model)");
1020	
1021	    // lm_head_weight shape: [vocab_size, hidden_size]
1022	    // For CodePredictor: vocab_size=2048 (codebook size), hidden_size=1024
1023	    // This is a fixed-size weight tensor that gets bound at runtime
1024	    int64_t const vocabSize = mModelConfig["vocab_size"].get<int64_t>();
1025	    int64_t const hiddenSize = mHiddenSize;
1026	
1027	    // Both context and generation profiles use the same shape since this is a weight tensor
1028	    result &= setOptimizationProfile(&contextProfile, binding_names::kLmHeadWeight, createDims({vocabSize, hiddenSize}),
1029	        createDims({vocabSize, hiddenSize}), createDims({vocabSize, hiddenSize}));
1030	    result &= setOptimizationProfile(&generationProfile, binding_names::kLmHeadWeight,
1031	        createDims({vocabSize, hiddenSize}), createDims({vocabSize, hiddenSize}), createDims({vocabSize, hiddenSize}));
1032	
1033	    if (!result)
1034	    {
1035	        LOG_ERROR("Failed to setup optimization profiles for lm_head_weight.");
1036	    }
1037	
1038	    return result;
1039	}
