1041	bool LLMBuilder::setupLoraProfiles(nvinfer1::IOptimizationProfile& contextProfile,
1042	    nvinfer1::IOptimizationProfile& generationProfile, nvinfer1::INetworkDefinition const& network)
1043	{
1044	    bool result = true;
1045	    if (mBuilderConfig.maxLoraRank == 0)
1046	    {
1047	        LOG_WARNING(
1048	            "Your model has dynamic LoRA, but max LoRA rank is 0. This is equivalent to no LoRA. Please set "
1049	            "--maxLoraRank to a positive value if you want to use LoRA.");
1050	        return true;
1051	    }
1052	
1053	    bool findLoraWeights = false;
1054	
1055	    for (int i = 0; i < network.getNbInputs(); ++i)
1056	    {
1057	        auto* input = network.getInput(i);
1058	        char const* const inputName = input->getName();
1059	        std::string_view const inputNameView = inputName;
1060	
1061	        if (inputNameView.find(binding_names::kLoraAPrefix) != std::string_view::npos)
1062	        {
1063	            if (!findLoraWeights)
1064	            {
1065	                findLoraWeights = true;
1066	            }
1067	            // For lora_A, the shape is [gemm_k, lora_rank]
1068	            auto dims = input->getDimensions();
1069	            if (dims.nbDims == 2)
1070	            {
1071	                int64_t gemm_k = dims.d[0];
1072	                result &= setOptimizationProfile(&contextProfile, inputName, createDims({gemm_k, 0}),    // min shape
1073	                    createDims({gemm_k, mBuilderConfig.maxLoraRank / 2}),                                // opt shape
1074	                    createDims({gemm_k, mBuilderConfig.maxLoraRank}));                                   // max shape
1075	                result &= setOptimizationProfile(&generationProfile, inputName, createDims({gemm_k, 0}), // min shape
1076	                    createDims({gemm_k, mBuilderConfig.maxLoraRank / 2}),                                // opt shape
1077	                    createDims({gemm_k, mBuilderConfig.maxLoraRank}));                                   // max shape
1078	            }
1079	        }
1080	        else if (inputNameView.find(binding_names::kLoraBPrefix) != std::string_view::npos)
1081	        {
1082	            if (!findLoraWeights)
1083	            {
1084	                findLoraWeights = true;
1085	            }
1086	            // For lora_B, the shape is [lora_rank, gemm_n]
1087	            auto dims = input->getDimensions();
1088	            if (dims.nbDims == 2)
1089	            {
1090	                int64_t gemm_n = dims.d[1];
1091	                result &= setOptimizationProfile(&contextProfile, inputName, createDims({0, gemm_n}),    // min shape
1092	                    createDims({mBuilderConfig.maxLoraRank / 2, gemm_n}),                                // opt shape
1093	                    createDims({mBuilderConfig.maxLoraRank, gemm_n}));                                   // max shape
1094	                result &= setOptimizationProfile(&generationProfile, inputName, createDims({0, gemm_n}), // min shape
1095	                    createDims({mBuilderConfig.maxLoraRank / 2, gemm_n}),                                // opt shape
1096	                    createDims({mBuilderConfig.maxLoraRank, gemm_n}));                                   // max shape
1097	            }
1098	        }
1099	    }
1100	
1101	    if (!findLoraWeights)
1102	    {
1103	        LOG_ERROR(
1104	            "Failed to find any LoRA weights inputs in the ONNX model. Have you inserted LoRA weights using "
1105	            "tensorrt-edgellm-insert-lora command?");
1106	        return false;
1107	    }
1108	
1109	    if (!result)
1110	    {
1111	        LOG_ERROR("Failed to setup optimization profiles at setupLoraProfiles().");
1112	    }
1113	
1114	    return result;
1115	}
