1117	bool LLMBuilder::setupKVCacheProfiles(
1118	    nvinfer1::IOptimizationProfile& contextProfile, nvinfer1::IOptimizationProfile& generationProfile)
1119	{
1120	    bool result = true;
1121	    // KV cache shape is [B, 2, num_kv_heads, 0 to max_kv_cache_capacity, head_dim]
1122	    for (int i = 0; i < mNbKVCacheInputs; ++i)
1123	    {
1124	        int64_t layerHeadSize = (!mPerLayerHeadSize.empty()) ? mPerLayerHeadSize[i] : mHeadSize;
1125	        int64_t layerNumKVHeads = (!mPerLayerNumKVHeads.empty()) ? mPerLayerNumKVHeads[i] : mNumKVHeads;
1126	        nvinfer1::Dims minKVCacheShape = createDims({1, 2, layerNumKVHeads, 0, layerHeadSize});
1127	        nvinfer1::Dims optKVCacheShape = createDims(
1128	            {mBuilderConfig.maxBatchSize, 2, layerNumKVHeads, mBuilderConfig.maxKVCacheCapacity, layerHeadSize});
1129	        nvinfer1::Dims maxKVCacheShape = createDims(
1130	            {mBuilderConfig.maxBatchSize, 2, layerNumKVHeads, mBuilderConfig.maxKVCacheCapacity, layerHeadSize});
1131	
1132	        result &= setOptimizationProfile(&contextProfile, binding_names::formatKVCacheName(i, true).c_str(),
1133	            minKVCacheShape, optKVCacheShape, maxKVCacheShape);
1134	        result &= setOptimizationProfile(&generationProfile, binding_names::formatKVCacheName(i, true).c_str(),
1135	            minKVCacheShape, optKVCacheShape, maxKVCacheShape);
1136	    }
1137	
1138	    return result;
1139	}
