1264	bool LLMBuilder::setupLinearAttentionSpecVerifyProfiles(nvinfer1::IOptimizationProfile& contextProfile,
1265	    nvinfer1::IOptimizationProfile& generationProfile, nvinfer1::INetworkDefinition const& network)
1266	{
1267	    if (mNumLinearAttnLayers == 0)
1268	    {
1269	        return true;
1270	    }
1271	
1272	    if (!hasInputBinding(network, binding_names::kSpecVerifyPhaseMarker))
1273	    {
1274	        LOG_ERROR("Hybrid MTP/DFlash base engine is missing input '%s'. Re-export the ONNX model.",
1275	            binding_names::kSpecVerifyPhaseMarker);
1276	        return false;
1277	    }
1278	
1279	    bool result = true;
1280	    result &= setOptimizationProfile(
1281	        &contextProfile, binding_names::kSpecVerifyPhaseMarker, createDims({0}), createDims({0}), createDims({0}));
1282	    result &= setOptimizationProfile(
1283	        &generationProfile, binding_names::kSpecVerifyPhaseMarker, createDims({0}), createDims({1}), createDims({1}));
1284	
1285	    auto setOptionalTreeProfile = [&](char const* inputName) {
1286	        if (!hasInputBinding(network, inputName))
1287	        {
1288	            return true;
1289	        }
1290	
1291	        int64_t const maxTreeTokens = std::max<int64_t>(1, mBuilderConfig.maxVerifyTreeSize);
1292	        bool ok = true;
1293	        ok &= setOptimizationProfile(&contextProfile, inputName, createDims({1, 1}),
1294	            createDims({mBuilderConfig.maxBatchSize, 1}), createDims({mBuilderConfig.maxBatchSize, maxTreeTokens}));
1295	        ok &= setOptimizationProfile(&generationProfile, inputName, createDims({1, 1}),
1296	            createDims({mBuilderConfig.maxBatchSize, std::max<int64_t>(1, maxTreeTokens / 2)}),
1297	            createDims({mBuilderConfig.maxBatchSize, maxTreeTokens}));
1298	        return ok;
1299	    };
1300	
1301	    result &= setOptionalTreeProfile(binding_names::kTreeParentIds);
1302	    result &= setOptionalTreeProfile(binding_names::kTreeDepths);
1303	
1304	    LOG_DEBUG("Set up hybrid linear-attention spec-verify profiles for %d recurrent layers", mNumLinearAttnLayers);
1305	    return result;
1306	}
