1310	// Speculative base and draft engines share one engineDir, so their external weight
1311	// files (e.g. external_int4_ffn_weights.safetensors) would otherwise overwrite
1312	// each other. Prefix only the draft files; the base keeps the original names
1313	// (matching the standalone non-speculative case), which is enough to avoid the
1314	// collision. copyConfig() and copyExternalWeightFiles() must agree on this name.
1315	std::string externalWeightDstName(std::string const& filename, bool specDraft)
1316	{
1317	    if (specDraft)
1318	    {
1319	        return "draft_" + filename;
1320	    }
1321	    return filename;
1322	}
