1325	bool LLMBuilder::copyConfig()
1326	{
1327	    // Determine config file name based on model type
1328	    std::string configFileName;
1329	    if (mBuilderConfig.specDraft)
1330	    {
1331	        configFileName = "draft_config.json";
1332	    }
1333	    else if (mBuilderConfig.specBase)
1334	    {
1335	        configFileName = "base_config.json";
1336	    }
1337	    else
1338	    {
1339	        configFileName = "config.json";
1340	    }
1341	
1342	    std::string const targetConfigPath = (mEngineDir / configFileName).string();
1343	
1344	    // Create a copy of mModelConfig and add builder config
1345	    Json configWithBuilder = mModelConfig;
1346	    configWithBuilder["builder_config"] = mBuilderConfig.toJson();
1347	
1348	    // Keep external weight file references in sync with the names written by
1349	    // copyExternalWeightFiles() (draft files get the "draft_" prefix) so the runtime loads the right file.
1350	    if (configWithBuilder.contains("external_weight_files") && configWithBuilder["external_weight_files"].is_array())
1351	    {
1352	        for (auto& fileEntry : configWithBuilder["external_weight_files"])
1353	        {
1354	            if (fileEntry.is_object() && fileEntry.contains("file") && fileEntry["file"].is_string())
1355	            {
1356	                fileEntry["file"]
1357	                    = externalWeightDstName(fileEntry["file"].get<std::string>(), mBuilderConfig.specDraft);
1358	            }
1359	        }
1360	    }
1361	
1362	    // Add detected num_deepstack_features if present (Qwen3VL models)
1363	    configWithBuilder["num_deepstack_features"] = mNumDeepstackFeatures;
1364	
1365	    // Emit per-layer KV cache configs for heterogeneous models (e.g. Gemma4).
1366	    // The runtime uses `kv_layer_configs` + normalized `layer_types` ("attention"/"mamba")
1367	    // to allocate per-layer KV cache tensors with the correct head dimensions.
1368	    if (!mPerLayerHeadSize.empty())
1369	    {
1370	        Json kvLayerConfigs = Json::array();
1371	        Json normalizedLayerTypes = Json::array();
1372	
1373	        // Preserve the per-position ordering from the input `layer_types` when it is
1374	        // present and complete: attention and mamba layers can interleave (e.g. Qwen3.5
1375	        // GDN hybrids place attention every Nth layer), and emitting "all attention then
1376	        // all mamba" would misplace every layer in the runtime routing table. Attention
1377	        // entries consume the per-layer head sizes in order; mamba entries carry no KV.
1378	        bool const haveInputLayerTypes = mModelConfig.contains("layer_types") && mModelConfig["layer_types"].is_array()
1379	            && mModelConfig["layer_types"].size() == static_cast<size_t>(mNbKVCacheInputs + mNumLinearAttnLayers);
1380	        if (haveInputLayerTypes)
1381	        {
1382	            int attnIdx = 0;
1383	            for (auto const& layerType : mModelConfig["layer_types"])
1384	            {
1385	                // Input layer_types are normalized to "attention" / "mamba" by the export.
1386	                if (layerType.is_string() && layerType.get<std::string>() == "mamba")
1387	                {
1388	                    normalizedLayerTypes.push_back("mamba");
1389	                    kvLayerConfigs.push_back(nullptr);
1390	                }
1391	                else
1392	                {
1393	                    // The total-size guard above does not constrain the attention/mamba split,
1394	                    // so a layer_types inconsistent with the ONNX (more attention entries than
1395	                    // KV cache inputs) would index past mPerLayerHeadSize. Fail clearly instead.
1396	                    check::check(attnIdx < static_cast<int>(mPerLayerHeadSize.size()),
1397	                        "copyConfig: layer_types has more attention layers than the " + std::to_string(mNbKVCacheInputs)
1398	                            + " KV cache input(s); config.json layer_types is inconsistent with the engine.");
1399	                    normalizedLayerTypes.push_back("attention");
1400	                    int64_t const layerNumKVHeads
1401	                        = (!mPerLayerNumKVHeads.empty()) ? mPerLayerNumKVHeads[attnIdx] : mNumKVHeads;
1402	                    kvLayerConfigs.push_back(
1403	                        Json{{"num_kv_heads", layerNumKVHeads}, {"head_dim", mPerLayerHeadSize[attnIdx]}});
1404	                    ++attnIdx;
1405	                }
1406	            }
1407	        }
1408	        else
1409	        {
1410	            // Legacy fallback (no per-position info): attention layers first, then mamba.
1411	            // Correct for pure-attention and all-attention heterogeneous models (e.g. Gemma4).
1412	            for (int i = 0; i < mNbKVCacheInputs; ++i)
1413	            {
1414	                normalizedLayerTypes.push_back("attention");
1415	                int64_t layerNumKVHeads = (!mPerLayerNumKVHeads.empty()) ? mPerLayerNumKVHeads[i] : mNumKVHeads;
1416	                kvLayerConfigs.push_back(Json{{"num_kv_heads", layerNumKVHeads}, {"head_dim", mPerLayerHeadSize[i]}});
1417	            }
1418	            for (int i = 0; i < mNumLinearAttnLayers; ++i)
1419	            {
1420	                normalizedLayerTypes.push_back("mamba");
1421	                kvLayerConfigs.push_back(nullptr);
1422	            }
1423	        }
1424	        configWithBuilder["layer_types"] = normalizedLayerTypes;
1425	        configWithBuilder["kv_layer_configs"] = kvLayerConfigs;
1426	    }
1427	
1428	    // Write updated config
1429	    std::ofstream targetConfigFile(targetConfigPath);
1430	    if (!targetConfigFile.is_open())
1431	    {
1432	        LOG_ERROR("Failed to open target config file: %s", targetConfigPath.c_str());
1433	        return false;
1434	    }
1435	    targetConfigFile << configWithBuilder.dump(2);
1436	    targetConfigFile.close();
1437	
1438	    LOG_INFO("Copied config.json with builder config to %s", targetConfigPath.c_str());
1439	    return true;
1440	}
