1442	bool LLMBuilder::copyTokenizerFiles()
1443	{
1444	    // Speculative draft models use the base model tokenizer.
1445	    if (mBuilderConfig.specDraft)
1446	    {
1447	        return true;
1448	    }
1449	
1450	    // Models that use embeddings as input (e.g., Talker, CodePredictor) don't need tokenizer
1451	    bool useEmbeddingsInput = mModelConfig.value("use_embeddings_input", false);
1452	    if (useEmbeddingsInput)
1453	    {
1454	        LOG_INFO("Skipping tokenizer files (model uses embeddings input)");
1455	        return true;
1456	    }
1457	
1458	    std::vector<std::string> tokenizerFiles
1459	        = {"tokenizer_config.json", "tokenizer.json", "processed_chat_template.json"};
1460	    bool allSuccess = true;
1461	
1462	    for (auto const& filename : tokenizerFiles)
1463	    {
1464	        std::string const srcPath = (mOnnxDir / filename).string();
1465	        std::string const dstPath = (mEngineDir / filename).string();
1466	
1467	        if (file_io::copyFile(srcPath, dstPath))
1468	        {
1469	            LOG_INFO("Copied tokenizer file: %s", filename.c_str());
1470	        }
1471	        else
1472	        {
1473	            LOG_WARNING("Failed to copy tokenizer file %s", filename.c_str());
1474	            allSuccess = false;
1475	        }
1476	    }
1477	
1478	    return allSuccess;
1479	}
