1490	        {
1491	            LOG_INFO("Copied d2t.safetensors to %s", targetD2tPath.c_str());
1492	        }
1493	        else
1494	        {
1495	            LOG_WARNING("Failed to copy d2t.safetensors to %s", targetD2tPath.c_str());
1496	            return false;
1497	        }
1498	    }
1499	
1500	    return true;
1501	}
1502	
1503	bool LLMBuilder::copyVocabMappingFiles()
1504	{
1505	    // Copy the vocab map sidecar if reduced vocabulary is used. Base engines
1506	    // consume vocab_map.safetensors; DFlash draft engines consume
1507	    // draft_vocab_map.safetensors. Pick the right filename based on the build
1508	    // role so the runtime finds the sidecar in mEngineDir.
1509	    if (mModelConfig.contains(binding_names::kReducedVocabSizeKey)
1510	        && mModelConfig[binding_names::kReducedVocabSizeKey].get<int32_t>() > 0)
1511	    {
1512	        char const* const vocabMapFileName
1513	            = mBuilderConfig.specDraft ? binding_names::kDraftVocabMapFileName : binding_names::kVocabMapFileName;
1514	        std::string const vocabMapPath = (mOnnxDir / vocabMapFileName).string();
1515	        std::string const targetVocabMapPath = (mEngineDir / vocabMapFileName).string();
1516	
1517	        if (!file_io::copyFile(vocabMapPath, targetVocabMapPath))
1518	        {
1519	            // The enclosing guard already proved reduced_vocab_size > 0, so the
1520	            // sidecar is required. Runtime will refuse to load (DFlashDecoder
1521	            // hard-errors when reducedVocabSize > 0 and the file is missing;
1522	            // base-model runtime falls back to no remap but produces wrong IDs).
1523	            // Fail the build instead of letting a broken engine ship.
1524	            LOG_ERROR(
1525	                "%s not found in %s but reduced_vocab_size > 0; the sidecar is "
1526	                "required for the runtime to remap reduced->full vocabulary IDs.",
1527	                vocabMapFileName, mOnnxDir.string().c_str());
1528	            return false;
1529	        }
1530	        LOG_INFO("Copied %s to %s", vocabMapFileName, targetVocabMapPath.c_str());
1531	    }
1532	
1533	    return true;
1534	}
1535	
1536	bool LLMBuilder::copyEmbeddingFile()
1537	{
1538	    // Speculative draft models use the base model embedding table.
1539	    if (mBuilderConfig.specDraft)
1540	    {
1541	        return true;
1542	    }
1543	
1544	    // Check if this is a Talker model (has text_projection.safetensors)
1545	    std::filesystem::path const textProjectionPath = mOnnxDir / "text_projection.safetensors";
1546	    if (std::filesystem::exists(textProjectionPath))
1547	    {
1548	        // Talker: copy embedding + text_projection + hidden_projection (optional, text-only TTS omits it)
1549	        LOG_INFO("Detected Talker model, copying projection files...");
1550	
1551	        std::vector<std::string> requiredFiles = {"embedding.safetensors", "text_projection.safetensors"};
1552	        std::vector<std::string> optionalFiles = {"text_embedding.safetensors", "hidden_projection.safetensors"};
1553	
1554	        bool allSuccess = true;
1555	        for (auto const& filename : requiredFiles)
1556	        {
1557	            std::string const srcPath = (mOnnxDir / filename).string();
1558	            std::string const dstPath = (mEngineDir / filename).string();
1559	
1560	            if (file_io::copyFile(srcPath, dstPath))
1561	            {
1562	                LOG_INFO("Copied %s", filename.c_str());
1563	            }
1564	            else
1565	            {
1566	                LOG_ERROR("Failed to copy %s", filename.c_str());
1567	                allSuccess = false;
1568	            }
1569	        }
1570	        for (auto const& filename : optionalFiles)
1571	        {
1572	            std::string const srcPath = (mOnnxDir / filename).string();
1573	            std::string const dstPath = (mEngineDir / filename).string();
1574	
1575	            if (file_io::copyFile(srcPath, dstPath))
1576	            {
1577	                LOG_INFO("Copied %s", filename.c_str());
1578	            }
1579	            else
1580	            {
1581	                LOG_INFO("Optional %s not found, skipping", filename.c_str());
1582	            }
1583	        }
1584	
1585	        return allSuccess;
1586	    }
1587	
1588	    // Check if this is a CodePredictor model (has codec_embeddings.safetensors)
1589	    std::filesystem::path const codecEmbedPath = mOnnxDir / "codec_embeddings.safetensors";
1590	    if (std::filesystem::exists(codecEmbedPath))
1591	    {
1592	        LOG_INFO("Detected CodePredictor model, copying codec files...");
1593	        std::vector<std::string> cpRequiredFiles = {"codec_embeddings.safetensors", "lm_heads.safetensors"};
1594	        std::vector<std::string> cpOptionalFiles = {"small_to_mtp_projection.safetensors"};
1595	        bool allSuccess = true;
1596	        for (auto const& filename : cpRequiredFiles)
1597	        {
1598	            std::string const srcPath = (mOnnxDir / filename).string();
1599	            std::string const dstPath = (mEngineDir / filename).string();
1600	            if (file_io::copyFile(srcPath, dstPath))
1601	            {
1602	                LOG_INFO("Copied %s", filename.c_str());
1603	            }
1604	            else
1605	            {
1606	                LOG_ERROR("Failed to copy required CodePredictor file: %s", filename.c_str());
1607	                allSuccess = false;
1608	            }
1609	        }
1610	        for (auto const& filename : cpOptionalFiles)
1611	        {
1612	            std::string const srcPath = (mOnnxDir / filename).string();
1613	            std::string const dstPath = (mEngineDir / filename).string();
1614	            if (file_io::copyFile(srcPath, dstPath))
1615	            {
1616	                LOG_INFO("Copied %s", filename.c_str());
1617	            }
1618	            else
1619	            {
1620	                LOG_INFO("Optional %s not found, skipping", filename.c_str());
1621	            }
1622	        }
1623	        return allSuccess;
1624	    }
1625	
1626	    // Copy embedding.safetensors for vanilla LLM models
1627	    std::string const embeddingPath = (mOnnxDir / "embedding.safetensors").string();
1628	    std::string const targetEmbeddingPath = (mEngineDir / "embedding.safetensors").string();
1629	
1630	    if (file_io::copyFile(embeddingPath, targetEmbeddingPath))
1631	    {
1632	        LOG_INFO("Copied embedding.safetensors to %s", targetEmbeddingPath.c_str());
1633	    }
1634	    else
1635	    {
1636	        LOG_ERROR(
1637	            "Failed to copy embedding.safetensors from %s to %s", embeddingPath.c_str(), targetEmbeddingPath.c_str());
1638	        return false;
1639	    }
1640	
1641	    if (mModelConfig.value("ple_enabled", false))
1642	    {
1643	        std::string const plePath = (mOnnxDir / binding_names::kPleEmbeddingFileName).string();
1644	        std::string const targetPlePath = (mEngineDir / binding_names::kPleEmbeddingFileName).string();
1645	        if (file_io::copyFile(plePath, targetPlePath))
1646	        {
1647	            LOG_INFO("Copied %s to %s", binding_names::kPleEmbeddingFileName, targetPlePath.c_str());
1648	        }
1649	        else
1650	        {
1651	            LOG_ERROR("Failed to copy %s from %s to %s", binding_names::kPleEmbeddingFileName, plePath.c_str(),
1652	                targetPlePath.c_str());
1653	            return false;
1654	        }
1655	    }
1656	
1657	    return true;
1658	}
1659	
1660	bool LLMBuilder::copyExternalWeightFiles()
1661	{
1662	    Json const externalWeightFiles = mModelConfig.value("external_weight_files", Json::array());
1663	    if (!externalWeightFiles.is_array())
1664	    {
1665	        LOG_ERROR("external_weight_files must be an array when present in config.json");
1666	        return false;
1667	    }
1668	    if (externalWeightFiles.empty())
1669	    {
1670	        return true;
1671	    }
1672	
1673	    bool allSuccess = true;
1674	    for (auto const& fileEntry : externalWeightFiles)
1675	    {
1676	        if (!fileEntry.is_object() || !fileEntry.contains("file") || !fileEntry["file"].is_string())
1677	        {
1678	            LOG_ERROR("Malformed external weight file entry: %s", fileEntry.dump().c_str());
1679	            return false;
1680	        }
1681	        std::string const filename = fileEntry["file"].get<std::string>();
1682	        std::string const dstFilename = externalWeightDstName(filename, mBuilderConfig.specDraft);
1683	        std::filesystem::path const srcPath = mOnnxDir / filename;
1684	        std::filesystem::path const dstPath = mEngineDir / dstFilename;
1685	
1686	        if (file_io::copyFile(srcPath.string(), dstPath.string()))
1687	        {
1688	            LOG_INFO("Copied external weight file: %s -> %s", filename.c_str(), dstFilename.c_str());
1689	        }
1690	        else
1691	        {
1692	            LOG_ERROR("Failed to copy external weight file %s from %s to %s", filename.c_str(),
1693	                srcPath.string().c_str(), dstPath.string().c_str());
1694	            allSuccess = false;
1695	        }
1696	    }
1697	    return allSuccess;
1698	}
1699	
1700	} // namespace builder
1701	} // namespace trt_edgellm
1702

