294	bool buildAndSerializeEngine(nvinfer1::IBuilder* builder, nvinfer1::INetworkDefinition* network,
295	    nvinfer1::IBuilderConfig* config, std::string const& engineFilePath)
296	{
297	    if (!builder || !network || !config)
298	    {
299	        LOG_ERROR("Invalid input: builder, network, or config is nullptr");
300	        return false;
301	    }
302	
303	    // Build serialized network
304	    auto engine = std::unique_ptr<nvinfer1::IHostMemory>(builder->buildSerializedNetwork(*network, *config));
305	    if (!engine)
306	    {
307	        LOG_ERROR("Failed to build serialized engine");
308	        return false;
309	    }
310	
311	    // Write to file
312	    std::ofstream ofs(engineFilePath, std::ios::out | std::ios::binary);
313	    if (!ofs)
314	    {
315	        LOG_ERROR("Failed to open file for writing: %s", engineFilePath.c_str());
316	        return false;
317	    }
318	
319	    ofs.write(static_cast<char const*>(engine->data()), engine->size());
320	    ofs.close();
321	
322	    if (!ofs)
323	    {
324	        LOG_ERROR("Failed to write engine to file: %s", engineFilePath.c_str());
325	        return false;
326	    }
327	
328	    LOG_INFO("Engine saved to %s", engineFilePath.c_str());
329	    return true;
