362	
363	    // Write updated config
364	    std::ofstream targetConfigFile(targetConfigPath);
365	    if (!targetConfigFile.is_open())
366	    {
367	        LOG_ERROR("Failed to open target config file: %s", targetConfigPath.c_str());
368	        return false;
369	    }
370	
371	    targetConfigFile << configWithBuilder.dump(2);
372	    targetConfigFile.close();
373	
374	    if (!targetConfigFile)
375	    {
376	        LOG_ERROR("Failed to write config file: %s", targetConfigPath.c_str());
377	        return false;
