41	bool VisualBuilder::build()
42	{
43	    // Load plugin library
44	    auto pluginHandles = loadEdgellmPluginLib();
45	
46	    // Parse model config
47	    if (!parseConfig())
48	    {
49	        return false;
50	    }
51	
52	    // Create builder and network
53	    auto [builder, network] = createBuilderAndNetwork();
54	    if (!builder || !network)
55	    {
56	        return false;
57	    }
58	
59	    // Parse ONNX model
60	    std::string const onnxPath = (mOnnxDir / "model.onnx").string();
61	    auto parser = parseOnnxModel(network.get(), onnxPath);
62	    if (!parser)
