77	    if (mBuilderConfig.profilingDetailed)
78	    {
79	        config->setProfilingVerbosity(nvinfer1::ProfilingVerbosity::kDETAILED);
80	        LOG_INFO("Profiling verbosity set to DETAILED");
81	    }
82	
83	    // Setup optimization profile
84	    if (!setupVisualOptimizationProfile(*builder.get(), *config.get(), *network.get()))
85	    {
