133	bool VisualBuilder::parseConfig()
134	{
135	    std::string const configPath = (mOnnxDir / "config.json").string();
136	    if (!loadJsonConfig(configPath, mModelConfig))
137	    {
138	        return false;
139	    }
140	
141	    // Check model version
142	    std::string modelVersion = mModelConfig.value(binding_names::kEdgellmVersion, "");
143	    version::checkVersion(modelVersion);
144	
145	    // Read model type from vision_config.model_type or top-level model_type
146	    std::string modelTypeStr;
147	    if (mModelConfig.contains(kVisionConfigKey) && mModelConfig[kVisionConfigKey].contains(kModelTypeKey))
148	    {
149	        modelTypeStr = mModelConfig[kVisionConfigKey][kModelTypeKey].get<std::string>();
150	    }
151	    else if (mModelConfig.contains(kModelTypeKey))
152	    {
153	        modelTypeStr = mModelConfig[kModelTypeKey].get<std::string>();
154	    }
155	    else
156	    {
157	        LOG_ERROR(
158	            "model_type not found in config.json (expected either vision_config.model_type or top-level model_type)");
159	        return false;
160	    }
161	
162	    mModelType = multimodal::stringToModelType(modelTypeStr);
163	
164	    switch (mModelType)
165	    {
166	    case multimodal::ModelType::INTERNVL:
167	        mNumChannels = mModelConfig[kVisionConfigKey]["num_channels"].get<int64_t>();
168	        mImageSizeH = mModelConfig[kVisionConfigKey]["image_size"][0].get<int64_t>();
169	        mImageSizeW = mModelConfig[kVisionConfigKey]["image_size"][1].get<int64_t>();
170	        break;
171	
172	    case multimodal::ModelType::PHI4MM:
173	        // Default Phi-4MM vision input
174	        mNumChannels = 3;
175	        // Prefer HF config's crop_size if available
176	        if (mModelConfig.contains(kEmbdLayerKey) && mModelConfig[kEmbdLayerKey].contains(kImageEmbdLayerKey)
177	            && mModelConfig[kEmbdLayerKey][kImageEmbdLayerKey].contains("crop_size"))
178	        {
179	            int64_t const crop = mModelConfig[kEmbdLayerKey][kImageEmbdLayerKey]["crop_size"].get<int64_t>();
180	            mImageSizeH = crop;
181	            mImageSizeW = crop;
182	        }
183	        else
184	        {
185	            LOG_INFO("Phi-4MM crop_size not found in config.json; defaulting to 448x448.");
186	            mImageSizeH = 448;
187	            mImageSizeW = 448;
188	        }
189	        break;
190	
191	    case multimodal::ModelType::NEMOTRON_OMNI_VISION_ENCODER:
192	    {
193	        mNumChannels = 3;
194	        if (mModelConfig.contains("force_image_size"))
195	        {
196	            int64_t const imgSize = mModelConfig["force_image_size"].get<int64_t>();
197	            mImageSizeH = imgSize;
198	            mImageSizeW = imgSize;
199	        }
200	        else
201	        {
202	            LOG_ERROR("Nemotron-Omni: force_image_size not found in config.json");
203	            return false;
204	        }
205	        LOG_INFO("Nemotron-Omni RADIO: channels=%ld, image_size=%ldx%ld", mNumChannels, mImageSizeH, mImageSizeW);
206	        break;
207	    }
208	
209	    case multimodal::ModelType::GEMMA4_UNIFIED_VISION:
210	    {
211	        // The exporter records the checkpoint's fixed per-image soft-token
212	        // budget in builder_config. The total request budget remains a
213	        // builder/CLI choice so a profile can support multiple images.
214	        if (mModelConfig.contains("builder_config"))
215	        {
216	            auto const& exportedBuilderConfig = mModelConfig["builder_config"];
217	            int64_t const exportedMaxPerImage
218	                = exportedBuilderConfig.value("max_image_tokens_per_image", mBuilderConfig.maxImageTokensPerImage);
219	            if (exportedMaxPerImage < 1 || mBuilderConfig.minImageTokens < 1
220	                || mBuilderConfig.maxImageTokens < mBuilderConfig.minImageTokens)
221	            {
222	                LOG_ERROR(
223	                    "Invalid Gemma4 Unified visual token bounds: requested min=%ld, requested max=%ld, "
224	                    "exported max_per_image=%ld",
225	                    mBuilderConfig.minImageTokens, mBuilderConfig.maxImageTokens, exportedMaxPerImage);
226	                return false;
227	            }
228	            mBuilderConfig.maxImageTokensPerImage
229	                = std::min({mBuilderConfig.maxImageTokensPerImage, exportedMaxPerImage, mBuilderConfig.maxImageTokens});
230	            LOG_INFO(
231	                "Gemma4 Unified visual profile: min=%ld, configurable total max=%ld, "
232	                "sidecar-capped max_per_image=%ld",
233	                mBuilderConfig.minImageTokens, mBuilderConfig.maxImageTokens, mBuilderConfig.maxImageTokensPerImage);
234	        }
235	        break;
236	    }
237	
238	    case multimodal::ModelType::UNKNOWN: LOG_ERROR("Unsupported model type: %s", modelTypeStr.c_str()); return false;
239	
240	    default: break;
241	    }
242	
243	    if (mModelConfig.value("use_trt_native_vit_attn", false))
244	    {
245	        logTrtNativeAttentionPath("ViTAttention");
246	    }
247	
248	    return true;
249	}
