251	bool VisualBuilder::setupVisualOptimizationProfile(
252	    nvinfer1::IBuilder& builder, nvinfer1::IBuilderConfig& config, nvinfer1::INetworkDefinition const& network)
253	{
254	    auto* visualProfile = builder.createOptimizationProfile();
255	    bool result = true;
256	
257	    switch (mModelType)
258	    {
259	    case multimodal::ModelType::QWEN2_VL:
260	    case multimodal::ModelType::QWEN2_5_VL:
261	    case multimodal::ModelType::QWEN3_VL:
262	    case multimodal::ModelType::QWEN3_5:
263	    case multimodal::ModelType::QWEN3_OMNI_VISION_ENCODER: result = setupQwenViTProfile(*visualProfile, network); break;
264	
265	    case multimodal::ModelType::INTERNVL:
266	    case multimodal::ModelType::PHI4MM: result = setupInternPhi4ViTProfile(*visualProfile); break;
267	
268	    case multimodal::ModelType::NEMOTRON_OMNI_VISION_ENCODER:
269	        result = setupNemotronOmniViTProfile(*visualProfile);
270	        break;
271	
272	    case multimodal::ModelType::GEMMA4_VISION: result = setupGemma4ViTProfile(*visualProfile, network); break;
273	
274	    case multimodal::ModelType::GEMMA4_UNIFIED_VISION:
275	        result = setupGemma4UnifiedVisionProfile(*visualProfile, network);
276	        break;
277	
278	    default: LOG_ERROR("Unsupported model type for visual encoder: %d", static_cast<int>(mModelType)); return false;
279	    }
280	
281	    if (!result)
282	    {
283	        LOG_ERROR("Failed to setup optimization profile");
284	        return false;
285	    }
286	
287	    LOG_DEBUG("%s", printOptimizationProfile(visualProfile, "visual_profile", &network).c_str());
288	
289	    config.addOptimizationProfile(visualProfile);
290	    return true;
291	}
292	
293	bool VisualBuilder::setupQwenViTProfile(
294	    nvinfer1::IOptimizationProfile& profile, nvinfer1::INetworkDefinition const& network)
295	{
296	    bool result = true;
297	
298	    // In Qwen-VL, HW is always 4ximageTokens because it equals to spatial_merge_size ** 2.
299	    int64_t minHW = mBuilderConfig.minImageTokens * 4;
300	    int64_t maxHW = mBuilderConfig.maxImageTokens * 4;
301	    int64_t optHW = (mBuilderConfig.minImageTokens + mBuilderConfig.maxImageTokens) / 2 * 4;
302	
303	    // Infer dimensions from the network
304	    int64_t inputDim = 0;
305	    int64_t ropeEmbedSize = 0;
306	
307	    for (int32_t i = 0; i < network.getNbInputs(); ++i)
308	    {
309	        auto* input = network.getInput(i);
310	        if (strcmp(input->getName(), binding_names::kVisualInput) == 0)
311	        {
312	            inputDim = input->getDimensions().d[1];
313	        }
314	        else if (strcmp(input->getName(), binding_names::kRotaryPosEmb) == 0)
315	        {
316	            ropeEmbedSize = input->getDimensions().d[1];
317	        }
318	    }
319	
320	    if (inputDim == 0)
321	    {
322	        LOG_ERROR("Cannot infer inputDim. Do you have proper ONNX input: %s?", binding_names::kVisualInput);
323	        return false;
324	    }
325	
326	    if (ropeEmbedSize == 0)
327	    {
328	        LOG_ERROR("Cannot infer ropeEmbedSize. Do you have proper ONNX input: %s?", binding_names::kRotaryPosEmb);
329	        return false;
330	    }
331	
332	    // Base inputs
333	    result &= setOptimizationProfile(&profile, binding_names::kVisualInput, createDims({minHW, inputDim}),
334	        createDims({optHW, inputDim}), createDims({maxHW, inputDim}));
335	    result &= setOptimizationProfile(&profile, binding_names::kRotaryPosEmb, createDims({minHW, ropeEmbedSize}),
336	        createDims({optHW, ropeEmbedSize}), createDims({maxHW, ropeEmbedSize}));
337	    int64_t maxNumImages = std::max<int64_t>(1, mBuilderConfig.maxImageTokens / mBuilderConfig.minImageTokens);
338	    result &= setOptimizationProfile(&profile, binding_names::kCuSeqlens, createDims({2}),
339	        createDims({maxNumImages + 1}), createDims({maxNumImages + 1}));
340	
341	    // kv_lengths is required when using TRT-native attention (TRT >= 11).
342	    // Read the flag from the exporter's config.json.
343	    mBuilderConfig.useTrtNativeVitAttn = mModelConfig.value("use_trt_native_vit_attn", false);
344	    if (mBuilderConfig.useTrtNativeVitAttn)
345	    {
346	        result &= setOptimizationProfile(&profile, binding_names::kKvLengths, createDims({2}),
347	            createDims({maxNumImages + 1}), createDims({maxNumImages + 1}));
348	    }
349	
350	    // max_seqlen_carrier is only present when using the ViTAttentionPlugin path (TRT 10).
351	    // The TRT-native attention path (TRT >= 11) does not emit this input.
352	    bool hasMaxSeqLenCarrier = false;
353	    for (int32_t i = 0; i < network.getNbInputs(); ++i)
354	    {
355	        if (strcmp(network.getInput(i)->getName(), binding_names::kMaxSeqLenCarrier) == 0)
356	        {
357	            hasMaxSeqLenCarrier = true;
358	            break;
359	        }
360	    }
361	    if (hasMaxSeqLenCarrier)
362	    {
363	        int32_t maxSeqLen = static_cast<int32_t>(mBuilderConfig.maxImageTokensPerImage * 4);
364	        result &= setOptimizationProfile(&profile, binding_names::kMaxSeqLenCarrier, createDims({1}),
365	            createDims({maxSeqLen / 2}), createDims({maxSeqLen}));
366	    }
367	
368	    // Additional inputs
369	    if (mModelType == multimodal::ModelType::QWEN2_5_VL)
370	    {
371	        // Use maxImageTokens as a safe upper bound for cumulative window sequence lengths.
372	        result &= setOptimizationProfile(&profile, binding_names::kCuWindowSeqlens, createDims({2}),
373	            createDims({mBuilderConfig.maxImageTokens}), createDims({mBuilderConfig.maxImageTokens}));
374	        if (mBuilderConfig.useTrtNativeVitAttn)
375	        {
376	            bool hasKvLengthsWindow = false;
377	            for (int32_t i = 0; i < network.getNbInputs(); ++i)
378	            {
379	                if (strcmp(network.getInput(i)->getName(), binding_names::kKvLengthsWindow) == 0)
380	                {
381	                    hasKvLengthsWindow = true;
382	                    break;
383	                }
384	            }
385	            if (hasKvLengthsWindow)
386	            {
387	                result &= setOptimizationProfile(&profile, binding_names::kKvLengthsWindow, createDims({2}),
388	                    createDims({mBuilderConfig.maxImageTokens}), createDims({mBuilderConfig.maxImageTokens}));
389	            }
390	        }
391	        result &= setOptimizationProfile(&profile, binding_names::kWindowIndex, createDims({minHW / 4}),
392	            createDims({optHW / 4}), createDims({maxHW / 4}));
393	        result &= setOptimizationProfile(&profile, binding_names::kReverseWindowIndex, createDims({minHW / 4}),
394	            createDims({optHW / 4}), createDims({maxHW / 4}));
395	    }
396	    else if (mModelType == multimodal::ModelType::QWEN3_VL || mModelType == multimodal::ModelType::QWEN3_5
397	        || mModelType == multimodal::ModelType::QWEN3_OMNI_VISION_ENCODER)
398	    {
399	        result &= setOptimizationProfile(&profile, binding_names::kFastPosEmbIdx, createDims({4, minHW}),
400	            createDims({4, optHW}), createDims({4, maxHW}));
401	        result &= setOptimizationProfile(&profile, binding_names::kFastPosEmbWeight, createDims({4, minHW}),
402	            createDims({4, optHW}), createDims({4, maxHW}));
403	    }
404	
405	    if (!result)
406	    {
407	        LOG_ERROR("Failed to setup optimization profile at setupQwenViTProfile().");
408	    }
409	
410	    return result;
411	}
412	
413	bool VisualBuilder::setupInternPhi4ViTProfile(nvinfer1::IOptimizationProfile& profile)
414	{
415	    bool result = true;
416	
417	    // For InternVL and Phi-4MM models, each image block contains 256 tokens (16x16 patch grid)
418	    // This is model-specific and comes from the vision encoder's patch size configuration
419	    constexpr int64_t kBlockLength = 256;
420	
421	    if (mBuilderConfig.minImageTokens % kBlockLength != 0 || mBuilderConfig.maxImageTokens % kBlockLength != 0)
422	    {
423	        LOG_ERROR(
424	            "minImageTokens and maxImageTokens must be divisible by %ld for InternVL/Phi4-MM ViT model.", kBlockLength);
425	        return false;
426	    }
427	
428	    int64_t minNumBlocks = mBuilderConfig.minImageTokens / kBlockLength;
429	    int64_t maxNumBlocks = mBuilderConfig.maxImageTokens / kBlockLength;
430	    int64_t optNumBlocks = (minNumBlocks + maxNumBlocks) / 2;
431	
432	    result &= setOptimizationProfile(&profile, binding_names::kVisualInput,
433	        createDims({minNumBlocks, mNumChannels, mImageSizeH, mImageSizeW}),
434	        createDims({optNumBlocks, mNumChannels, mImageSizeH, mImageSizeW}),
435	        createDims({maxNumBlocks, mNumChannels, mImageSizeH, mImageSizeW}));
436	
437	    return result;
438	}
439	
440	bool VisualBuilder::setupNemotronOmniViTProfile(nvinfer1::IOptimizationProfile& profile)
441	{
442	    bool result = true;
443	
444	    // Tokens per tile: (H / patch_size * downsample_ratio)^2
445	    int64_t const patchSize = mModelConfig["patch_size"].get<int64_t>();
446	    double const downsampleRatio = mModelConfig["downsample_ratio"].get<double>();
447	    int64_t const tokensPerSide = static_cast<int64_t>(mImageSizeH / patchSize * downsampleRatio);
448	    int64_t const kTokensPerBlock = tokensPerSide * tokensPerSide;
449	
450	    int64_t maxNumBlocks = std::max<int64_t>(1, mBuilderConfig.maxImageTokens / kTokensPerBlock);
451	    int64_t minNumBlocks = std::max<int64_t>(1, mBuilderConfig.minImageTokens / kTokensPerBlock);
452	    int64_t optNumBlocks = (minNumBlocks + maxNumBlocks) / 2;
453	
454	    result &= setOptimizationProfile(&profile, binding_names::kVisualInput,
455	        createDims({minNumBlocks, mNumChannels, mImageSizeH, mImageSizeW}),
456	        createDims({optNumBlocks, mNumChannels, mImageSizeH, mImageSizeW}),
457	        createDims({maxNumBlocks, mNumChannels, mImageSizeH, mImageSizeW}));
458	
459	    if (!result)
460	    {
461	        LOG_ERROR("Failed to setup Nemotron-Omni ViT optimization profile");
462	    }
463	    return result;
464	}
465	
466	bool VisualBuilder::setupGemma4ViTProfile(
467	    nvinfer1::IOptimizationProfile& profile, nvinfer1::INetworkDefinition const& network)
468	{
469	    bool result = true;
470	
471	    auto const& visionConfig = mModelConfig[kVisionConfigKey];
472	    int64_t const poolingKernelSize = visionConfig.value("pooling_kernel_size", 3);
473	    int64_t const patchesPerSoftToken = poolingKernelSize * poolingKernelSize;
474	    int64_t const minSoftTokens = mBuilderConfig.minImageTokens;
475	    int64_t const maxSoftTokens = mBuilderConfig.maxImageTokens;
476	    int64_t const optSoftTokens = std::max<int64_t>(minSoftTokens, (minSoftTokens + maxSoftTokens) / 2);
477	    int64_t const minPatches = minSoftTokens * patchesPerSoftToken;
478	    int64_t const optPatches = optSoftTokens * patchesPerSoftToken;
479	    int64_t const maxPatches = maxSoftTokens * patchesPerSoftToken;
480	
481	    int64_t inputDim = 0;
482	    int64_t ropeEmbedSize = 0;
483	    bool hasMaxSeqLenCarrier = false;
484	    bool hasKvLengths = false;
485	    for (int32_t i = 0; i < network.getNbInputs(); ++i)
486	    {
487	        auto* input = network.getInput(i);
488	        if (strcmp(input->getName(), binding_names::kVisualInput) == 0)
489	        {
490	            inputDim = input->getDimensions().d[1];
491	        }
492	        else if (strcmp(input->getName(), binding_names::kRotaryPosEmb) == 0)
493	        {
494	            ropeEmbedSize = input->getDimensions().d[1];
495	        }
496	        else if (strcmp(input->getName(), binding_names::kMaxSeqLenCarrier) == 0)
497	        {
498	            hasMaxSeqLenCarrier = true;
499	        }
500	        else if (strcmp(input->getName(), binding_names::kKvLengths) == 0)
501	        {
502	            hasKvLengths = true;
503	        }
504	    }
505	    if (inputDim == 0)
506	    {
507	        LOG_ERROR("Cannot infer inputDim. Do you have proper ONNX input: %s?", binding_names::kVisualInput);
508	        return false;
509	    }
510	    if (ropeEmbedSize == 0)
511	    {
512	        LOG_ERROR("Cannot infer ropeEmbedSize. Do you have proper ONNX input: %s?", binding_names::kRotaryPosEmb);
513	        return false;
514	    }
515	
516	    result &= setOptimizationProfile(&profile, binding_names::kVisualInput, createDims({minPatches, inputDim}),
517	        createDims({optPatches, inputDim}), createDims({maxPatches, inputDim}));
518	    result &= setOptimizationProfile(&profile, binding_names::kPixelPositionIds, createDims({minPatches, 2}),
519	        createDims({optPatches, 2}), createDims({maxPatches, 2}));
520	    result &= setOptimizationProfile(&profile, binding_names::kRotaryPosEmb, createDims({minPatches, ropeEmbedSize}),
521	        createDims({optPatches, ropeEmbedSize}), createDims({maxPatches, ropeEmbedSize}));
522	    result &= setOptimizationProfile(&profile, binding_names::kPoolingWeights, createDims({minSoftTokens, minPatches}),
523	        createDims({optSoftTokens, optPatches}), createDims({maxSoftTokens, maxPatches}));
524	
525	    int64_t const maxNumImages = std::max<int64_t>(1, maxSoftTokens / mBuilderConfig.minImageTokens);
526	    result &= setOptimizationProfile(&profile, binding_names::kCuSeqlens, createDims({2}),
527	        createDims({maxNumImages + 1}), createDims({maxNumImages + 1}));
528	
529	    mBuilderConfig.useTrtNativeVitAttn = mModelConfig.value("use_trt_native_vit_attn", false);
530	    if (mBuilderConfig.useTrtNativeVitAttn)
531	    {
532	        if (!hasKvLengths)
533	        {
534	            LOG_ERROR("Gemma4 config requests TRT-native ViT attention but ONNX is missing kv_lengths");
535	            return false;
536	        }
537	        result &= setOptimizationProfile(&profile, binding_names::kKvLengths, createDims({2}),
538	            createDims({maxNumImages + 1}), createDims({maxNumImages + 1}));
539	    }
540	    if (hasMaxSeqLenCarrier)
541	    {
542	        int64_t const maxSeqLen = mBuilderConfig.maxImageTokensPerImage * patchesPerSoftToken;
543	        result &= setOptimizationProfile(&profile, binding_names::kMaxSeqLenCarrier, createDims({1}),
544	            createDims({std::max<int64_t>(1, maxSeqLen / 2)}), createDims({maxSeqLen}));
545	    }
546	
547	    if (!result)
548	    {
549	        LOG_ERROR("Failed to setup Gemma4 ViT optimization profile");
550	    }
551	    return result;
552	}
553	
554	bool VisualBuilder::setupGemma4UnifiedVisionProfile(
555	    nvinfer1::IOptimizationProfile& profile, nvinfer1::INetworkDefinition const& network)
556	{
557	    int64_t inputDim = 0;
558	    int64_t positionDim = 0;
559	    for (int32_t i = 0; i < network.getNbInputs(); ++i)
560	    {
561	        auto const* input = network.getInput(i);
562	        if (strcmp(input->getName(), binding_names::kVisualInput) == 0)
563	        {
564	            auto const dims = input->getDimensions();
565	            if (dims.nbDims == 2)
566	            {
567	                inputDim = dims.d[1];
568	            }
569	        }
570	        else if (strcmp(input->getName(), binding_names::kPixelPositionIds) == 0)
571	        {
572	            auto const dims = input->getDimensions();
573	            if (dims.nbDims == 2)
574	            {
575	                positionDim = dims.d[1];
576	            }
577	        }
578	    }
579	
580	    constexpr int64_t kUnifiedPatchDim = 48 * 48 * 3;
581	    if (inputDim != kUnifiedPatchDim || positionDim != 2)
582	    {
583	        LOG_ERROR(
584	            "Gemma4 Unified visual ONNX inputs must be input [N,%ld] and pixel_position_ids [N,2]; "
585	            "got trailing dimensions %ld and %ld",
586	            kUnifiedPatchDim, inputDim, positionDim);
587	        return false;
588	    }
589	    if (mBuilderConfig.minImageTokens < 1 || mBuilderConfig.maxImageTokens < mBuilderConfig.minImageTokens)
590	    {
591	        LOG_ERROR("Gemma4 Unified visual profile requires 1 <= minImageTokens <= maxImageTokens");
592	        return false;
593	    }
594	
595	    int64_t const minPatches = mBuilderConfig.minImageTokens;
596	    int64_t const maxPatches = mBuilderConfig.maxImageTokens;
597	    int64_t const optPatches = minPatches + (maxPatches - minPatches) / 2;
598	    bool result = true;
599	    result &= setOptimizationProfile(&profile, binding_names::kVisualInput, createDims({minPatches, inputDim}),
600	        createDims({optPatches, inputDim}), createDims({maxPatches, inputDim}));
601	    result &= setOptimizationProfile(&profile, binding_names::kPixelPositionIds, createDims({minPatches, 2}),
602	        createDims({optPatches, 2}), createDims({maxPatches, 2}));
603	    if (!result)
604	    {
605	        LOG_ERROR("Failed to setup Gemma4 Unified vision optimization profile");
606	    }
607	    return result;
608	}
609	
610	bool VisualBuilder::copyConfig()
611	{
612	    // Save merged config (original model config + builder config) to engine directory
613	    if (!saveConfigWithBuilderInfo(mEngineDir, mModelConfig, mBuilderConfig.toJson()))
614	    {
615	        LOG_ERROR("Failed to save config to engine directory");
616	        return false;
617	    }
618	
619	    // Copy preprocessor_config.json if it exists (needed for image preprocessing at runtime)
620	    std::string preprocessorConfigPath = (mOnnxDir / "preprocessor_config.json").string();
621	    if (std::filesystem::exists(preprocessorConfigPath))
622	    {
623	        std::string targetPreprocessorConfigPath = (mEngineDir / "preprocessor_config.json").string();
624	        std::filesystem::copy(
625	            preprocessorConfigPath, targetPreprocessorConfigPath, std::filesystem::copy_options::overwrite_existing);
626	        LOG_INFO("Copied preprocessor config to %s", targetPreprocessorConfigPath.c_str());
627	    }
628	    else
629	    {
630	        LOG_WARNING("No preprocessor config found at %s", preprocessorConfigPath.c_str());
631	    }
632	
633	    return true;
634	}
635	
636	} // namespace builder
637	} // namespace trt_edgellm
